command.text:
        /* <flatten type="Javascript"> */
var f = this, errorMessage = (f._language == 'v' ? 'Trường <span class="Highlight">Giờ vào</span> phải nhỏ hơn <span class="Highlight">Giờ ra</span>.' : '<span class="Highlight">Time In</span> must be less than <span class="Highlight">Time Out</span>.');
var c1 = f.getItemValue('gio_tu'), c2 = f.getItemValue('gio_den');
var t1 = parseInt(c1.substr(0, 2)) * 60 + parseInt(c1.substr(3, 2)) + (f.getItemValue('hs_tu') ? 1440 : 0), t2 = parseInt(c2.substr(0, 2)) * 60 + parseInt(c2.substr(3, 2)) + (f.getItemValue('hs_den') ? 1440 : 0);
if (t1 >= t2) {
  $func.hideWait(f.get_id());
  f._checked = false;
  $message.show(errorMessage, String.format('$find(\'{0}\').focus(\'{1}\');', f.get_id(), 'gio_tu'));
}
/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function active$EmployeeWorkdayAdjusting(f) {f.add_onResponseComplete(on$EmployeeWorkdayAdjusting$ResponseComplete);}
function onchange$EmployeeWorkdayAdjusting$IDNumber(o) {o.parentForm.request('IDNumber', 'IDNumber', ['ma_nv']);}
function close$EmployeeWorkdayAdjusting(f) {try {f.remove_onResponseComplete(on$EmployeeWorkdayAdjusting$ResponseComplete)} catch (ex) {}}
function on$EmployeeWorkdayAdjusting$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Checking':
      objectBehavior$Dir$Irregular.checkCode(f, 'ma_ca_ct');
      break;
    case 'IDNumber':
      f.setItemControlBehavior('stt_rec', result[0].Value, true);
      break;
    default:
      break;
  }
}
/* </flatten> */
      &ScriptIrregular;
